import React, { useState, useMemo } from 'react';
import { Calendar, Search, Banknote, CreditCard, ChevronDown, ReceiptText, Clock, ShoppingBag, Power, TrendingUp, AlertCircle, X, Package, Printer, FileText } from 'lucide-react';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { Sale, Product, DayClosure, ProductClosureSnapshot } from '../types';

interface SalesHistoryProps {
  sales: Sale[];
  products: Product[];
  closures: DayClosure[];
  onDeleteSale: (id: string) => void;
  dateRange: { start: string; end: string };
  setDateRange: React.Dispatch<React.SetStateAction<{ start: string; end: string }>>;
}

const SalesHistory: React.FC<SalesHistoryProps> = ({ sales, products, closures, onDeleteSale, dateRange, setDateRange }) => {
  const [activeView, setActiveView] = useState<'sales' | 'closures'>('sales');
  const [expandedSale, setExpandedSale] = useState<string | null>(null);
  const [expandedClosure, setExpandedClosure] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const todayStr = new Date().toISOString().split('T')[0];

  const filteredSales = useMemo(() => {
    const start = new Date(dateRange.start).setHours(0,0,0,0);
    const end = new Date(dateRange.end).setHours(23, 59, 59, 999);

    return sales.filter(s => {
      const matchesDate = s.date >= start && s.date <= end;
      const matchesSearch = s.id.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           s.items.some(i => i.name.toLowerCase().includes(searchTerm.toLowerCase()));
      return matchesDate && matchesSearch;
    }).sort((a, b) => b.date - a.date);
  }, [sales, dateRange, searchTerm]);

  const filteredClosures = useMemo(() => {
    const start = new Date(dateRange.start).setHours(0,0,0,0);
    const end = new Date(dateRange.end).setHours(23, 59, 59, 999);
    return closures.filter(c => c.startTime >= start && c.startTime <= end)
                  .sort((a, b) => b.startTime - a.startTime);
  }, [closures, dateRange]);

  const todayStats = useMemo(() => {
    const start = new Date(todayStr).setHours(0,0,0,0);
    const end = new Date(todayStr).setHours(23,59,59,999);
    const todaySales = sales.filter(s => s.date >= start && s.date <= end);
    const total = todaySales.reduce((acc, s) => acc + s.total, 0);
    return { total, count: todaySales.length };
  }, [sales, todayStr]);

  const setToday = () => {
    setDateRange({ start: todayStr, end: todayStr });
  };

  const generateClosurePDF = (closure: DayClosure) => {
    const doc = new jsPDF();
    const businessName = localStorage.getItem('gourmet_settings') 
      ? JSON.parse(localStorage.getItem('gourmet_settings')!).businessName 
      : 'GourmetPOS';

    // Header
    doc.setFillColor(16, 185, 129);
    doc.rect(0, 0, 210, 40, 'F');
    doc.setTextColor(255, 255, 255);
    doc.setFontSize(24);
    doc.setFont('helvetica', 'bold');
    doc.text(businessName, 14, 25);

    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    doc.text('REPORTE DE CIERRE DIARIO', 14, 33);

    // Closure Info
    doc.setTextColor(50, 50, 50);
    doc.setFontSize(12);
    doc.text(`Fecha: ${new Date(closure.startTime).toLocaleDateString()}`, 14, 50);
    doc.text(`Apertura: ${new Date(closure.startTime).toLocaleTimeString()}`, 14, 57);
    doc.text(`Cierre: ${closure.endTime ? new Date(closure.endTime).toLocaleTimeString() : 'En curso'}`, 14, 64);

    // Financial Summary Table
    const totalVentas = closure.totalCashSales + closure.totalTransferSales;
    const esperado = closure.initialCash + closure.totalCashSales;
    const diferencia = (closure.finalCashReal || 0) - esperado;

    autoTable(doc, {
      startY: 75,
      head: [['Concepto Financiero', 'Monto']],
      body: [
        ['Fondo Inicial (Caja)', `$${closure.initialCash.toLocaleString()}`],
        ['Ventas en Efectivo', `$${closure.totalCashSales.toLocaleString()}`],
        ['Ventas por Transferencia', `$${closure.totalTransferSales.toLocaleString()}`],
        ['Total Ventas del Turno', `$${totalVentas.toLocaleString()}`],
        ['Efectivo Esperado', `$${esperado.toLocaleString()}`],
        ['Efectivo Real Contado', `$${closure.finalCashReal?.toLocaleString() || '---'}`],
        ['Diferencia / Balance', { content: `$${diferencia.toLocaleString()}`, styles: { textColor: diferencia < 0 ? [220, 38, 38] : [16, 185, 129], fontStyle: 'bold' } }],
      ],
      theme: 'striped',
      headStyles: { fillColor: [51, 65, 85] },
      margin: { left: 14, right: 14 }
    });

    // Inventory Table
    doc.setFontSize(14);
    doc.setFont('helvetica', 'bold');
    doc.text('Reconciliación de Inventario', 14, (doc as any).lastAutoTable.finalY + 15);

    const inventoryBody = (Object.values(closure.productSnapshots) as ProductClosureSnapshot[])
      .filter(s => s.soldQuantity > 0 || s.initialStock > 0)
      .map(s => [
        s.name,
        `${s.initialStock.toFixed(2)} ${s.unit}`,
        `${s.soldQuantity.toFixed(2)} ${s.unit}`,
        `${(s.initialStock - s.soldQuantity).toFixed(2)} ${s.unit}`
      ]);

    autoTable(doc, {
      startY: (doc as any).lastAutoTable.finalY + 20,
      head: [['Producto', 'Stock Inicial', 'Cant. Vendida', 'Stock Final']],
      body: inventoryBody,
      theme: 'grid',
      headStyles: { fillColor: [16, 185, 129] },
      columnStyles: {
        2: { fontStyle: 'bold' },
        3: { fontStyle: 'bold', textColor: [16, 185, 129] }
      }
    });

    if (closure.notes) {
      doc.setFontSize(10);
      doc.setTextColor(100);
      doc.text(`Notas: ${closure.notes}`, 14, (doc as any).lastAutoTable.finalY + 10);
    }

    doc.save(`Cierre_${new Date(closure.startTime).toISOString().split('T')[0]}.pdf`);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20">
      <header className="flex flex-col xl:flex-row justify-between items-start xl:items-center gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight flex items-center gap-3">
            <ReceiptText className="text-emerald-600" size={32} />
            Historial de Operaciones
          </h2>
          <p className="text-slate-500 font-medium">Revisando ventas del {dateRange.start === dateRange.end ? (dateRange.start === todayStr ? 'Hoy (Día actual)' : dateRange.start) : 'periodo seleccionado'}</p>
        </div>

        <div className="flex flex-col sm:flex-row items-center gap-4 w-full xl:w-auto">
          <button 
            onClick={setToday}
            className={`px-4 py-3 rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all flex items-center gap-2 ${dateRange.start === todayStr && dateRange.end === todayStr ? 'bg-emerald-600 text-white shadow-lg' : 'bg-white text-slate-400 border border-slate-100 hover:bg-slate-50'}`}
          >
            <Clock size={16} />
            Ir a Hoy
          </button>

          <div className="flex items-center gap-2 bg-white p-2 rounded-2xl shadow-sm border border-slate-100 w-full sm:w-auto">
            <Calendar size={18} className="text-slate-400 ml-2" />
            <input 
              type="date" 
              className="bg-transparent border-none focus:ring-0 text-sm font-bold text-slate-700 w-full sm:w-auto"
              value={dateRange.start}
              onChange={e => setDateRange(prev => ({ ...prev, start: e.target.value }))}
            />
            <span className="text-slate-300">|</span>
            <input 
              type="date" 
              className="bg-transparent border-none focus:ring-0 text-sm font-bold text-slate-700 w-full sm:w-auto"
              value={dateRange.end}
              onChange={e => setDateRange(prev => ({ ...prev, end: e.target.value }))}
            />
          </div>
        </div>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-sm flex items-center gap-5">
          <div className="w-14 h-14 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center justify-center shrink-0">
            <TrendingUp size={28} />
          </div>
          <div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Total Hoy ({new Date().toLocaleDateString()})</p>
            <h4 className="text-2xl font-black text-slate-800">${todayStats.total.toLocaleString()}</h4>
          </div>
        </div>
        <div className="bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-sm flex items-center gap-5">
          <div className="w-14 h-14 bg-blue-50 text-blue-600 rounded-2xl flex items-center justify-center shrink-0">
            <ShoppingBag size={28} />
          </div>
          <div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Pedidos Hoy</p>
            <h4 className="text-2xl font-black text-slate-800">{todayStats.count}</h4>
          </div>
        </div>
        <div className="bg-slate-900 p-6 rounded-[2.5rem] shadow-xl flex items-center gap-5">
          <div className="w-14 h-14 bg-white/10 text-emerald-400 rounded-2xl flex items-center justify-center shrink-0">
            <Power size={28} />
          </div>
          <div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Estado Caja</p>
            <h4 className="text-xl font-black text-white">Sincronizado</h4>
          </div>
        </div>
      </div>

      <div className="flex bg-white p-1.5 rounded-2xl shadow-sm border border-slate-100 w-fit">
        <button onClick={() => setActiveView('sales')} className={`px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeView === 'sales' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-50'}`}>Lista de Ventas</button>
        <button onClick={() => setActiveView('closures')} className={`px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeView === 'closures' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-50'}`}>Cierres de Turno</button>
      </div>

      {activeView === 'sales' ? (
        <div className="space-y-6">
          <div className="flex justify-between items-center px-4">
             <h3 className="text-xl font-black text-slate-800 flex items-center gap-2"><Clock className="text-emerald-500" /> Línea de Tiempo</h3>
             <div className="relative max-w-xs w-full">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input 
                  type="text" 
                  placeholder="Buscar venta o producto..." 
                  className="w-full pl-10 pr-4 py-3 bg-white border border-slate-200 rounded-2xl text-sm font-bold shadow-sm"
                  value={searchTerm}
                  onChange={e => setSearchTerm(e.target.value)}
                />
             </div>
          </div>

          <div className="bg-white rounded-[3rem] shadow-sm border border-slate-100 overflow-hidden">
            <table className="w-full text-left">
              <thead>
                <tr className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em] border-b border-slate-50">
                  <th className="py-6 pl-10">Fecha / Hora</th>
                  <th className="py-6">Método de Pago</th>
                  <th className="py-6 text-right pr-10">Monto Final</th>
                  <th className="py-6 w-10"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {filteredSales.map(sale => {
                  const isToday = new Date(sale.date).toISOString().split('T')[0] === todayStr;
                  return (
                    <React.Fragment key={sale.id}>
                      <tr onClick={() => setExpandedSale(expandedSale === sale.id ? null : sale.id)} className={`hover:bg-slate-50 cursor-pointer transition-colors ${isToday ? 'bg-emerald-50/20' : ''}`}>
                        <td className="py-6 pl-10">
                          <div className="flex flex-col">
                             <span className="font-black text-slate-800 flex items-center gap-2">
                               {new Date(sale.date).toLocaleDateString()}
                               {isToday && <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span>}
                             </span>
                             <span className="text-[10px] text-slate-400 font-bold uppercase">{new Date(sale.date).toLocaleTimeString()}</span>
                          </div>
                        </td>
                        <td className="py-6">
                          <div className="flex items-center gap-2">
                            {sale.paymentMethod === 'cash' ? <Banknote size={16} className="text-emerald-500" /> : <CreditCard size={16} className="text-blue-500" />}
                            <span className={`px-3 py-1 rounded-xl text-[10px] font-black uppercase ${sale.paymentMethod === 'cash' ? 'bg-emerald-50 text-emerald-600' : 'bg-blue-50 text-blue-600'}`}>
                              {sale.paymentMethod === 'cash' ? 'Efectivo' : 'Transferencia'}
                            </span>
                          </div>
                        </td>
                        <td className="py-6 text-right pr-10 font-black text-slate-900 text-xl">${sale.total.toLocaleString()}</td>
                        <td className="py-6 pr-6">
                          <ChevronDown size={20} className={`text-slate-300 transition-transform ${expandedSale === sale.id ? 'rotate-180' : ''}`} />
                        </td>
                      </tr>
                      {expandedSale === sale.id && (
                        <tr className="bg-slate-50/50">
                          <td colSpan={4} className="p-8">
                             <div className="grid grid-cols-1 md:grid-cols-2 gap-8 bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
                                <div>
                                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Detalle del Pedido</p>
                                  <ul className="space-y-3">
                                    {sale.items.map((item, idx) => (
                                      <li key={idx} className="flex justify-between items-center py-2 border-b border-slate-50 last:border-0">
                                        <span className="font-bold text-slate-700">{item.name} <span className="text-slate-400 ml-1">x {item.quantity} {item.unit}</span></span>
                                        <span className="font-black text-slate-800">${(item.price * item.quantity).toLocaleString()}</span>
                                      </li>
                                    ))}
                                  </ul>
                                </div>
                                <div className="flex flex-col justify-between items-end">
                                   <div className="text-right">
                                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Identificador Único</p>
                                      <p className="font-mono text-xs text-slate-500">#{sale.id}</p>
                                   </div>
                                   <button 
                                     onClick={(e) => { e.stopPropagation(); onDeleteSale(sale.id); }}
                                     className="text-red-500 font-black text-[10px] uppercase tracking-widest flex items-center gap-2 hover:bg-red-50 px-4 py-2 rounded-xl transition-all"
                                   >
                                     <X size={14} /> Anular Transacción
                                   </button>
                                </div>
                             </div>
                          </td>
                        </tr>
                      )}
                    </React.Fragment>
                  );
                })}
                {filteredSales.length === 0 && (
                  <tr><td colSpan={4} className="py-32 text-center text-slate-300 font-black uppercase tracking-widest text-xs">No se encontraron ventas en esta fecha</td></tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      ) : (
        <div className="space-y-6">
           <h3 className="text-xl font-black text-slate-800 px-4 flex items-center gap-2"><Power className="text-blue-500" /> Historial de Turnos Abiertos/Cerrados</h3>
           <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
             {filteredClosures.map(c => {
                const totalVentas = c.totalCashSales + c.totalTransferSales;
                const esperado = c.initialCash + c.totalCashSales;
                const diferencia = (c.finalCashReal || 0) - esperado;
                const isToday = new Date(c.startTime).toISOString().split('T')[0] === todayStr;
                const isExpanded = expandedClosure === c.id;

                return (
                  <div key={c.id} className={`bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100 space-y-6 ${isToday ? 'ring-2 ring-emerald-500/20' : ''} ${isExpanded ? 'md:col-span-2' : ''}`}>
                    <div className="flex justify-between items-start">
                      <div className="cursor-pointer" onClick={() => setExpandedClosure(isExpanded ? null : c.id)}>
                        <p className="text-lg font-black text-slate-800 flex items-center gap-2">
                          {new Date(c.startTime).toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long' })}
                          {isToday && <span className="text-[10px] bg-emerald-100 text-emerald-700 px-2 py-0.5 rounded-lg">HOY</span>}
                          <ChevronDown size={18} className={`text-slate-300 transition-transform ${isExpanded ? 'rotate-180' : ''}`} />
                        </p>
                        <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{new Date(c.startTime).toLocaleTimeString()} - {c.endTime ? new Date(c.endTime).toLocaleTimeString() : 'En curso'}</p>
                      </div>
                      <div className="flex gap-2">
                        <button 
                          onClick={() => generateClosurePDF(c)}
                          title="Imprimir Reporte PDF"
                          className="p-3 bg-slate-50 text-slate-600 hover:bg-emerald-50 hover:text-emerald-600 rounded-2xl transition-all border border-slate-100"
                        >
                          <Printer size={18} />
                        </button>
                        <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase flex items-center ${c.status === 'open' ? 'bg-emerald-50 text-emerald-600' : 'bg-slate-100 text-slate-500'}`}>
                          {c.status === 'open' ? 'Turno Activo' : 'Cerrado'}
                        </span>
                      </div>
                    </div>

                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                      <div className="p-4 bg-slate-50 rounded-2xl">
                         <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Total Vendido</p>
                         <p className="text-xl font-black text-slate-800">${totalVentas.toLocaleString()}</p>
                      </div>
                      <div className="p-4 bg-slate-50 rounded-2xl">
                         <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Balance Caja</p>
                         <p className={`text-xl font-black ${diferencia >= 0 ? 'text-emerald-600' : 'text-red-500'}`}>
                           {diferencia >= 0 ? '+' : ''}{diferencia.toLocaleString()}
                         </p>
                      </div>
                      <div className="p-4 bg-slate-50 rounded-2xl">
                         <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Efectivo Real</p>
                         <p className="text-xl font-black text-slate-800">${c.finalCashReal?.toLocaleString() || '---'}</p>
                      </div>
                      <div className="p-4 bg-slate-50 rounded-2xl">
                         <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Fondo Inicial</p>
                         <p className="text-xl font-black text-slate-800">${c.initialCash.toLocaleString()}</p>
                      </div>
                    </div>

                    {isExpanded && c.productSnapshots && (
                      <div className="pt-6 border-t border-slate-50 animate-in fade-in slide-in-from-top-4">
                        <div className="flex items-center justify-between mb-4">
                          <div className="flex items-center gap-2">
                            <Package size={18} className="text-emerald-500" />
                            <h4 className="text-sm font-black text-slate-800 uppercase tracking-widest">Reconciliación de Inventario del Turno</h4>
                          </div>
                          <button 
                            onClick={() => generateClosurePDF(c)}
                            className="text-[9px] font-black text-emerald-600 uppercase tracking-widest flex items-center gap-1 hover:underline"
                          >
                            <FileText size={12} /> Exportar Detalle Completo
                          </button>
                        </div>
                        <div className="bg-slate-50/50 rounded-3xl overflow-hidden border border-slate-100">
                           <table className="w-full text-left text-xs">
                             <thead className="bg-white">
                               <tr className="text-[9px] font-black text-slate-400 uppercase tracking-widest">
                                 <th className="px-6 py-4">Producto</th>
                                 <th className="px-6 py-4 text-center">Stock Inicial</th>
                                 <th className="px-6 py-4 text-center">Vendido</th>
                                 <th className="px-6 py-4 text-right">Stock Final</th>
                               </tr>
                             </thead>
                             <tbody className="divide-y divide-slate-100">
                               {(Object.values(c.productSnapshots) as ProductClosureSnapshot[]).filter(s => s.soldQuantity > 0 || s.initialStock > 0).map(s => {
                                 const final = s.initialStock - s.soldQuantity;
                                 return (
                                   <tr key={s.productId} className="hover:bg-white transition-colors">
                                     <td className="px-6 py-4">
                                       <p className="font-bold text-slate-800">{s.name}</p>
                                     </td>
                                     <td className="px-6 py-4 text-center font-mono text-slate-500">{s.initialStock.toFixed(2)} {s.unit}</td>
                                     <td className="px-6 py-4 text-center">
                                       <span className="px-2 py-0.5 bg-red-50 text-red-600 rounded font-black">-{s.soldQuantity.toFixed(2)}</span>
                                     </td>
                                     <td className="px-6 py-4 text-right font-black text-emerald-600 font-mono">{final.toFixed(2)} {s.unit}</td>
                                   </tr>
                                 );
                               })}
                             </tbody>
                           </table>
                        </div>
                      </div>
                    )}

                    {c.notes && (
                      <div className="mt-4 p-4 bg-amber-50 rounded-2xl flex gap-3 text-amber-700">
                        <AlertCircle size={16} className="shrink-0" />
                        <p className="text-[10px] font-bold italic">Observaciones: {c.notes}</p>
                      </div>
                    )}
                  </div>
                );
             })}
             {filteredClosures.length === 0 && (
               <div className="col-span-2 py-32 text-center bg-white rounded-[3rem] border border-dashed border-slate-200">
                  <Power size={48} className="mx-auto mb-4 text-slate-100" />
                  <p className="text-slate-300 font-black uppercase tracking-widest text-xs">Sin actividad de turnos en este periodo</p>
               </div>
             )}
           </div>
        </div>
      )}
    </div>
  );
};

export default SalesHistory;

import React, { useState, useMemo } from 'react';
import { Search, ShoppingCart, Trash2, CreditCard, Banknote, Plus, Minus, Calendar, Power, AlertCircle, X, CheckCircle2, ArrowRight, FileText } from 'lucide-react';
import { Product, Category, Sale, SaleItem, DayClosure } from '../types';

interface POSProps {
  products: Product[];
  categories: Category[];
  activeClosure: DayClosure | null;
  onCompleteSale: (sale: Sale) => void;
  onOpenDay: (initialCash: number) => void;
  onCloseDay: (finalCashReal: number, notes?: string) => void;
}

const POS: React.FC<POSProps> = ({ products, categories, activeClosure, onCompleteSale, onOpenDay, onCloseDay }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('all');
  const [cart, setCart] = useState<SaleItem[]>([]);
  const [paymentMethod, setPaymentMethod] = useState<'cash' | 'transfer'>('cash');
  const [showOpenModal, setShowOpenModal] = useState(false);
  const [showCloseModal, setShowCloseModal] = useState(false);
  const [showSuccessModal, setShowSuccessModal] = useState(false);
  const [lastSale, setLastSale] = useState<Sale | null>(null);
  const [amount, setAmount] = useState<number>(0);
  const [notes, setNotes] = useState('');

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase()) || p.code.includes(searchTerm);
      const matchesCategory = selectedCategory === 'all' || p.categoryId === selectedCategory;
      return matchesSearch && matchesCategory;
    });
  }, [products, searchTerm, selectedCategory]);

  const addToCart = (product: Product) => {
    if (!activeClosure) {
      alert("Debes abrir la caja antes de vender.");
      return;
    }
    if (product.stock <= 0) {
      alert("Producto sin stock");
      return;
    }
    const existing = cart.find(item => item.productId === product.id);
    if (existing) {
      if (existing.quantity >= product.stock) {
        alert("No hay más stock disponible");
        return;
      }
      setCart(cart.map(item => item.productId === product.id ? { ...item, quantity: item.quantity + 1 } : item));
    } else {
      setCart([...cart, { 
        productId: product.id, 
        name: product.name, 
        price: product.salePrice, 
        quantity: 1,
        unit: product.unit
      }]);
    }
  };

  const updateCartQuantity = (productId: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.productId === productId) {
        const newQty = item.quantity + delta;
        const product = products.find(p => p.id === productId);
        if (newQty <= 0) return null;
        if (product && newQty > product.stock) {
          alert("Excede el stock disponible");
          return item;
        }
        return { ...item, quantity: parseFloat(newQty.toFixed(2)) };
      }
      return item;
    }).filter(Boolean) as SaleItem[]);
  };

  const cartTotal = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);

  const handleCheckout = () => {
    if (cart.length === 0) return;
    const newSale: Sale = {
      id: Math.random().toString(36).substr(2, 9),
      items: [...cart],
      total: cartTotal,
      paymentMethod,
      date: Date.now(),
      closureId: activeClosure?.id
    };
    onCompleteSale(newSale);
    setLastSale(newSale);
    setShowSuccessModal(true);
    setCart([]);
  };

  const isNearExpiry = (date?: string) => {
    if (!date) return false;
    const expiry = new Date(date).getTime();
    const diff = expiry - new Date().getTime();
    return diff < (1000 * 60 * 60 * 24 * 7);
  };

  return (
    <div className="flex flex-col h-full space-y-6">
      {/* Turn Control Header */}
      <div className="flex justify-between items-center bg-white p-4 rounded-[2rem] border border-slate-100 shadow-sm">
        <div className="flex items-center gap-4">
          <div className={`p-3 rounded-2xl ${activeClosure ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>
            <Power size={24} />
          </div>
          <div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Estado del Turno</p>
            <p className="font-black text-slate-800 uppercase tracking-tight">
              {activeClosure ? `Abierto - Iniciado: ${new Date(activeClosure.startTime).toLocaleTimeString()}` : 'Caja Cerrada'}
            </p>
          </div>
        </div>
        {activeClosure ? (
          <button 
            onClick={() => setShowCloseModal(true)}
            className="flex items-center gap-2 bg-slate-900 text-white px-6 py-3 rounded-2xl hover:bg-slate-800 transition-all font-black text-xs uppercase tracking-widest shadow-xl shadow-slate-200"
          >
            Cerrar Turno del Día
          </button>
        ) : (
          <button 
            onClick={() => setShowOpenModal(true)}
            className="flex items-center gap-2 bg-emerald-600 text-white px-6 py-3 rounded-2xl hover:bg-emerald-700 transition-all font-black text-xs uppercase tracking-widest shadow-xl shadow-emerald-200"
          >
            Abrir Día de Ventas
          </button>
        )}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 flex-1">
        {/* Product Selection */}
        <div className="lg:col-span-8 flex flex-col space-y-4">
          <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex flex-col md:flex-row gap-4">
            <div className="relative flex-1">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Buscar producto..." 
                className="w-full pl-10 pr-4 py-2 bg-slate-50 border-none rounded-xl focus:ring-2 focus:ring-emerald-500 font-bold"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
            <select 
              className="px-4 py-2 bg-slate-50 border-none rounded-xl focus:ring-2 focus:ring-emerald-500 font-bold outline-none"
              value={selectedCategory}
              onChange={(e) => setSelectedCategory(e.target.value)}
            >
              <option value="all">Categorías</option>
              {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-3 xl:grid-cols-4 gap-4 overflow-y-auto no-scrollbar pb-10">
            {filteredProducts.map(product => {
              const nearExpiry = isNearExpiry(product.expiryDate);
              const isOutOfStock = product.stock <= 0;
              return (
                <button
                  key={product.id}
                  disabled={isOutOfStock}
                  onClick={() => addToCart(product)}
                  className={`bg-white p-3 rounded-3xl shadow-sm border-2 transition-all text-left group flex flex-col h-fit ${isOutOfStock ? 'opacity-40 grayscale border-transparent' : 'border-transparent hover:border-emerald-400 hover:scale-[1.02]'} ${nearExpiry && !isOutOfStock ? 'border-amber-200' : ''}`}
                >
                  <div className="aspect-square rounded-2xl bg-slate-50 mb-3 overflow-hidden relative">
                    {product.image ? (
                      <img src={product.image} alt={product.name} className="w-full h-full object-cover" />
                    ) : (
                      <div className="w-full h-full flex items-center justify-center text-slate-200">
                        <ShoppingCart size={40} />
                      </div>
                    )}
                    <div className="absolute bottom-2 right-2 bg-white/90 backdrop-blur px-2 py-1 rounded-lg text-[10px] font-black text-emerald-600 shadow-sm">
                      {product.stock} {product.unit}
                    </div>
                  </div>
                  <h3 className="font-bold text-slate-800 line-clamp-2 text-sm leading-tight mb-2">{product.name}</h3>
                  <div className="flex justify-between items-center mt-auto">
                    <p className="text-emerald-600 font-black">${product.salePrice.toLocaleString()}</p>
                    <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">{product.unit}</p>
                  </div>
                </button>
              );
            })}
          </div>
        </div>

        {/* Cart Panel */}
        <div className="lg:col-span-4 bg-white rounded-[3rem] shadow-xl border border-slate-100 flex flex-col h-[calc(100vh-14rem)] sticky top-8">
          <div className="p-8 border-b">
            <h2 className="text-xl font-black flex items-center gap-3">
              <ShoppingCart className="text-emerald-600" size={24} />
              Venta Gourmet
            </h2>
          </div>

          <div className="flex-1 overflow-y-auto p-6 space-y-4 no-scrollbar">
            {cart.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-slate-300 opacity-50 space-y-3">
                <ShoppingCart size={64} />
                <p className="font-black uppercase tracking-[0.2em] text-xs">Esperando Pedido...</p>
              </div>
            ) : (
              cart.map(item => {
                const product = products.find(p => p.id === item.productId);
                const stockAfter = product ? product.stock - item.quantity : 0;
                return (
                  <div key={item.productId} className="flex flex-col gap-2 p-4 bg-slate-50 rounded-[1.5rem] border border-slate-100">
                    <div className="flex items-center gap-4">
                      <div className="flex-1">
                        <h4 className="font-black text-slate-800 text-sm line-clamp-1">{item.name}</h4>
                        <p className="text-emerald-600 font-bold text-xs">${(item.price * item.quantity).toLocaleString()}</p>
                      </div>
                      <div className="flex items-center gap-3 bg-white rounded-2xl border border-slate-200 p-1.5">
                        <button onClick={() => updateCartQuantity(item.productId, -1)} className="p-1 hover:text-red-500 transition-colors">
                          <Minus size={16} />
                        </button>
                        <span className="w-8 text-center font-black text-sm">{item.quantity}</span>
                        <button onClick={() => updateCartQuantity(item.productId, 1)} className="p-1 hover:text-emerald-600 transition-colors">
                          <Plus size={16} />
                        </button>
                      </div>
                    </div>
                    <div className="flex justify-between items-center px-1">
                      <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Impacto en Inventario</span>
                      <span className="text-[9px] font-bold text-slate-500">Quedarán: <span className={stockAfter < 5 ? 'text-red-500 font-black' : 'text-emerald-600 font-black'}>{stockAfter.toFixed(2)} {item.unit}</span></span>
                    </div>
                  </div>
                );
              })
            )}
          </div>

          <div className="p-8 bg-slate-50 rounded-b-[3rem] space-y-6 border-t border-slate-100">
            <div className="flex items-center justify-between font-black text-3xl text-slate-800">
              <span className="text-sm text-slate-400 uppercase tracking-widest">Total</span>
              <span>${cartTotal.toLocaleString()}</span>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <button 
                onClick={() => setPaymentMethod('cash')}
                className={`flex flex-col items-center justify-center p-4 rounded-2xl border-2 transition-all ${paymentMethod === 'cash' ? 'bg-emerald-50 border-emerald-500 text-emerald-700' : 'bg-white border-transparent text-slate-400'}`}
              >
                < Banknote size={24} />
                <span className="text-[10px] font-black mt-2 uppercase tracking-widest">Efectivo</span>
              </button>
              <button 
                onClick={() => setPaymentMethod('transfer')}
                className={`flex flex-col items-center justify-center p-4 rounded-2xl border-2 transition-all ${paymentMethod === 'transfer' ? 'bg-blue-50 border-blue-500 text-blue-700' : 'bg-white border-transparent text-slate-400'}`}
              >
                <CreditCard size={24} />
                <span className="text-[10px] font-black mt-2 uppercase tracking-widest">Transferencia</span>
              </button>
            </div>

            <button 
              disabled={cart.length === 0 || !activeClosure}
              onClick={handleCheckout}
              className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-black py-5 rounded-[2rem] shadow-xl shadow-emerald-100 transition-all active:scale-95 disabled:opacity-30 disabled:grayscale"
            >
              CONFIRMAR VENTA
            </button>
          </div>
        </div>
      </div>

      {/* MODAL: Success & Inventory Feedback */}
      {showSuccessModal && lastSale && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-6 bg-slate-900/60 backdrop-blur-md">
          <div className="bg-white w-full max-w-lg rounded-[3.5rem] shadow-2xl overflow-hidden animate-in zoom-in duration-300">
            <div className="p-10 text-center">
              <div className="w-20 h-20 bg-emerald-50 text-emerald-600 rounded-[2rem] flex items-center justify-center mx-auto mb-6">
                <CheckCircle2 size={40} />
              </div>
              <h3 className="text-2xl font-black text-slate-800 mb-2">Venta Exitosa</h3>
              <p className="text-slate-400 font-bold uppercase tracking-widest text-xs mb-8">Resumen de Inventario Actualizado</p>

              <div className="bg-slate-50 rounded-[2rem] p-6 mb-8 text-left space-y-4">
                {lastSale.items.map(item => {
                  const product = products.find(p => p.id === item.productId);
                  return (
                    <div key={item.productId} className="flex justify-between items-center border-b border-slate-200/50 pb-3 last:border-0 last:pb-0">
                       <div>
                         <p className="font-black text-slate-800 text-sm">{item.name}</p>
                         <p className="text-[10px] text-slate-400 font-bold">Deducido: -{item.quantity} {item.unit}</p>
                       </div>
                       <div className="text-right">
                         <p className="text-xs font-black text-emerald-600">Stock Actual</p>
                         <p className="font-mono text-sm font-bold">{product?.stock.toFixed(2)} {item.unit}</p>
                       </div>
                    </div>
                  );
                })}
              </div>

              <button 
                onClick={() => { setShowSuccessModal(false); setLastSale(null); }}
                className="w-full bg-slate-900 text-white font-black py-5 rounded-[2rem] shadow-xl uppercase tracking-widest"
              >
                Continuar Vendiendo
              </button>
            </div>
          </div>
        </div>
      )}

      {/* MODAL: Abrir Caja */}
      {showOpenModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-900/60 backdrop-blur-md">
          <div className="bg-white w-full max-w-md rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in duration-300">
            <div className="p-10 text-center">
              <div className="w-20 h-20 bg-emerald-50 text-emerald-600 rounded-[2rem] flex items-center justify-center mx-auto mb-6">
                <Power size={40} />
              </div>
              <h3 className="text-2xl font-black text-slate-800 mb-2">Apertura de Día</h3>
              <p className="text-slate-400 font-bold uppercase tracking-widest text-xs mb-8">Ingresa el fondo inicial de caja</p>

              <div className="space-y-4 text-left">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Monto en Efectivo</label>
                <input 
                  type="number" 
                  className="w-full px-8 py-5 bg-slate-50 border-none rounded-[2rem] focus:ring-4 focus:ring-emerald-100 font-black text-2xl text-center"
                  value={amount}
                  onChange={e => setAmount(Number(e.target.value))}
                  autoFocus
                />
                <button 
                  onClick={() => { onOpenDay(amount); setShowOpenModal(false); setAmount(0); }}
                  className="w-full bg-emerald-600 text-white font-black py-5 rounded-[2rem] shadow-xl shadow-emerald-100 mt-4 uppercase tracking-widest"
                >
                  Iniciar Turno
                </button>
                <button onClick={() => setShowOpenModal(false)} className="w-full py-4 text-slate-400 font-bold uppercase text-[10px] tracking-widest">Cancelar</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* MODAL: Cerrar Caja */}
      {showCloseModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-900/60 backdrop-blur-md">
          <div className="bg-white w-full max-w-lg rounded-[3.5rem] shadow-2xl overflow-hidden animate-in zoom-in duration-300">
            <div className="p-10">
              <div className="flex justify-between items-center mb-10">
                 <h3 className="text-3xl font-black text-slate-800">Cierre de Caja</h3>
                 <button onClick={() => setShowCloseModal(false)} className="p-2 hover:bg-slate-50 rounded-full"><X/></button>
              </div>

              <div className="grid grid-cols-2 gap-4 mb-8">
                <div className="bg-slate-50 p-6 rounded-[2rem]">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Ventas Efectivo</p>
                  <p className="text-2xl font-black text-slate-800">${activeClosure?.totalCashSales.toLocaleString()}</p>
                </div>
                <div className="bg-slate-50 p-6 rounded-[2rem]">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Ventas Transf.</p>
                  <p className="text-2xl font-black text-slate-800">${activeClosure?.totalTransferSales.toLocaleString()}</p>
                </div>
                <div className="col-span-2 bg-emerald-50 p-6 rounded-[2rem] border border-emerald-100">
                  <p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest mb-1">Efectivo Esperado (Fondo + Ventas)</p>
                  <p className="text-3xl font-black text-emerald-700">${((activeClosure?.initialCash || 0) + (activeClosure?.totalCashSales || 0)).toLocaleString()}</p>
                </div>
              </div>

              <div className="space-y-6">
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4 mb-2 block">Efectivo Real en Caja</label>
                  <input 
                    type="number" 
                    placeholder="Monto contado..."
                    className="w-full px-8 py-5 bg-white border-2 border-slate-100 rounded-[2rem] focus:ring-4 focus:ring-emerald-100 font-black text-2xl text-center"
                    value={amount}
                    onChange={e => setAmount(Number(e.target.value))}
                  />
                </div>
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4 mb-2 block">Notas adicionales</label>
                  <textarea 
                    className="w-full px-8 py-4 bg-slate-50 border-none rounded-3xl focus:ring-4 focus:ring-emerald-100 font-bold text-sm h-24"
                    value={notes}
                    onChange={e => setNotes(e.target.value)}
                    placeholder="Ejem: Diferencia por vueltos, gastos menores..."
                  />
                </div>

                <div className="p-4 bg-blue-50 rounded-2xl flex items-center gap-3 text-blue-700 mb-2">
                  <FileText size={20} />
                  <p className="text-[10px] font-bold">Tras cerrar, podrás descargar el reporte PDF detallado con inventario en la pestaña "Historial".</p>
                </div>

                <button 
                  onClick={() => { onCloseDay(amount, notes); setShowCloseModal(false); setAmount(0); setNotes(''); }}
                  className="w-full bg-slate-900 text-white font-black py-5 rounded-[2rem] shadow-xl uppercase tracking-widest"
                >
                  Finalizar Turno y Guardar Historial
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default POS;

import React, { useState, useEffect, useCallback } from 'react';
import { ShoppingCart, Package, BarChart3, Menu, X, Tag, TrendingUp, ReceiptText, Settings as SettingsIcon, LogOut, UserCircle } from 'lucide-react';
import { Product, Category, Sale, InventoryMovement, FinancialSettings, AutoSaveConfig, Role, User, Permission, DayClosure, ProductClosureSnapshot } from './types';
import POS from './components/POS';
import Products from './components/Products';
import Inventory from './components/Inventory';
import Statistics from './components/Statistics';
import Insights from './components/Insights';
import SalesHistory from './components/SalesHistory';
import Settings from './components/Settings';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Permission>('pos');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // Persistence State
  const [products, setProducts] = useState<Product[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);
  const [movements, setMovements] = useState<InventoryMovement[]>([]);
  const [closures, setClosures] = useState<DayClosure[]>([]);
  const [activeClosure, setActiveClosure] = useState<DayClosure | null>(null);
  const [financialSettings, setFinancialSettings] = useState<FinancialSettings>({
    businessName: 'GourmetPOS',
    initialInvestment: 1000,
    workerSalaryRate: 1.5
  });

  const [dateRange, setDateRange] = useState(() => {
    const today = new Date().toISOString().split('T')[0];
    return { start: today, end: today };
  });

  const [roles, setRoles] = useState<Role[]>([
    { id: 'admin', name: 'Administrador', permissions: ['pos', 'inventory', 'products', 'stats', 'insights', 'sales-history', 'settings'] },
    { id: 'seller', name: 'Vendedor', permissions: ['pos', 'sales-history'] }
  ]);
  const [users, setUsers] = useState<User[]>([
    { id: '1', username: 'admin', roleId: 'admin' }
  ]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  const [autoSaveConfig, setAutoSaveConfig] = useState<AutoSaveConfig>({
    enabled: false,
    lastSaved: null
  });
  const [directoryHandle, setDirectoryHandle] = useState<FileSystemDirectoryHandle | null>(null);
  const [isSaving, setIsSaving] = useState(false);

  // Load Data
  useEffect(() => {
    const savedProducts = localStorage.getItem('gourmet_products');
    const savedCategories = localStorage.getItem('gourmet_categories');
    const savedSales = localStorage.getItem('gourmet_sales');
    const savedMovements = localStorage.getItem('gourmet_movements');
    const savedClosures = localStorage.getItem('gourmet_closures');
    const savedActiveClosure = localStorage.getItem('gourmet_active_closure');
    const savedSettings = localStorage.getItem('gourmet_settings');
    const savedAutoSave = localStorage.getItem('gourmet_autosave_config');
    const savedRoles = localStorage.getItem('gourmet_roles');
    const savedUsers = localStorage.getItem('gourmet_users');

    if (savedProducts) setProducts(JSON.parse(savedProducts));
    if (savedCategories) setCategories(JSON.parse(savedCategories));
    if (savedSales) setSales(JSON.parse(savedSales));
    if (savedMovements) setMovements(JSON.parse(savedMovements));
    if (savedClosures) setClosures(JSON.parse(savedClosures));
    if (savedActiveClosure) setActiveClosure(JSON.parse(savedActiveClosure));
    if (savedSettings) setFinancialSettings(JSON.parse(savedSettings));
    if (savedAutoSave) setAutoSaveConfig(JSON.parse(savedAutoSave));
    if (savedRoles) setRoles(JSON.parse(savedRoles));
    if (savedUsers) setUsers(JSON.parse(savedUsers));
  }, []);

  // Sync LocalStorage
  useEffect(() => {
    localStorage.setItem('gourmet_products', JSON.stringify(products));
    localStorage.setItem('gourmet_categories', JSON.stringify(categories));
    localStorage.setItem('gourmet_sales', JSON.stringify(sales));
    localStorage.setItem('gourmet_movements', JSON.stringify(movements));
    localStorage.setItem('gourmet_closures', JSON.stringify(closures));
    localStorage.setItem('gourmet_active_closure', JSON.stringify(activeClosure));
    localStorage.setItem('gourmet_settings', JSON.stringify(financialSettings));
    localStorage.setItem('gourmet_autosave_config', JSON.stringify(autoSaveConfig));
    localStorage.setItem('gourmet_roles', JSON.stringify(roles));
    localStorage.setItem('gourmet_users', JSON.stringify(users));
  }, [products, categories, sales, movements, closures, activeClosure, financialSettings, autoSaveConfig, roles, users]);

  const addMovement = useCallback((productId: string, quantity: number, type: 'in' | 'out', reason: string) => {
    const newMovement: InventoryMovement = {
      id: Math.random().toString(36).substr(2, 9),
      productId, quantity, type, reason, date: Date.now()
    };
    setMovements(prev => [newMovement, ...prev]);
    setProducts(prev => prev.map(p => p.id === productId ? { ...p, stock: type === 'in' ? p.stock + quantity : p.stock - quantity } : p));
  }, []);

  const openDay = (initialCash: number) => {
    const productSnapshots: Record<string, ProductClosureSnapshot> = {};
    products.forEach(p => {
      // Forzamos stock inicial entero para el historial de cierre como se solicitó
      productSnapshots[p.id] = {
        productId: p.id,
        name: p.name,
        unit: p.unit,
        initialStock: Math.round(p.stock),
        soldQuantity: 0
      };
    });

    const newClosure: DayClosure = {
      id: `closure-${Date.now()}`,
      startTime: Date.now(),
      endTime: null,
      initialCash,
      totalCashSales: 0,
      totalTransferSales: 0,
      finalCashReal: null,
      status: 'open',
      productSnapshots
    };
    setActiveClosure(newClosure);
  };

  const closeDay = (finalCashReal: number, notes?: string) => {
    if (!activeClosure) return;
    const closedClosure: DayClosure = {
      ...activeClosure,
      endTime: Date.now(),
      finalCashReal,
      notes,
      status: 'closed'
    };
    setClosures(prev => [closedClosure, ...prev]);
    setActiveClosure(null);
  };

  const completeSale = useCallback((sale: Sale) => {
    const saleWithSession = { ...sale, closureId: activeClosure?.id };
    setSales(prev => [saleWithSession, ...prev]);

    if (activeClosure) {
      setActiveClosure(prev => {
        if (!prev) return prev;
        const newSnapshots = { ...prev.productSnapshots };
        sale.items.forEach(item => {
          if (newSnapshots[item.productId]) {
            newSnapshots[item.productId].soldQuantity += item.quantity;
          } else {
            const product = products.find(p => p.id === item.productId);
            newSnapshots[item.productId] = {
              productId: item.productId,
              name: item.name,
              unit: item.unit,
              initialStock: product ? Math.round(product.stock) : 0,
              soldQuantity: item.quantity
            };
          }
        });

        return {
          ...prev,
          totalCashSales: sale.paymentMethod === 'cash' ? prev.totalCashSales + sale.total : prev.totalCashSales,
          totalTransferSales: sale.paymentMethod === 'transfer' ? prev.totalTransferSales + sale.total : prev.totalTransferSales,
          productSnapshots: newSnapshots
        };
      });
    }

    sale.items.forEach(item => addMovement(item.productId, item.quantity, 'out', `Venta #${sale.id.slice(-4)}`));
  }, [addMovement, activeClosure, products]);

  const deleteSale = useCallback((saleId: string) => {
    const saleToDelete = sales.find(s => s.id === saleId);
    if (!saleToDelete) return;
    if (window.confirm("¿Está seguro de eliminar esta venta? El stock será devuelto al inventario.")) {
      saleToDelete.items.forEach(item => addMovement(item.productId, item.quantity, 'in', `Anulación venta #${saleId.slice(-4)}`));

      if (activeClosure && saleToDelete.closureId === activeClosure.id) {
        setActiveClosure(prev => {
          if (!prev) return prev;
          const newSnapshots = { ...prev.productSnapshots };
          saleToDelete.items.forEach(item => {
            if (newSnapshots[item.productId]) {
              newSnapshots[item.productId].soldQuantity -= item.quantity;
            }
          });
          return {
            ...prev,
            totalCashSales: saleToDelete.paymentMethod === 'cash' ? prev.totalCashSales - saleToDelete.total : prev.totalCashSales,
            totalTransferSales: saleToDelete.paymentMethod === 'transfer' ? prev.totalTransferSales - saleToDelete.total : prev.totalTransferSales,
            productSnapshots: newSnapshots
          };
        });
      }

      setSales(prev => prev.filter(s => s.id !== saleId));
    }
  }, [sales, addMovement, activeClosure]);

  const handleImport = (data: any) => {
    if (data.products) setProducts(data.products);
    if (data.categories) setCategories(data.categories);
    if (data.sales) setSales(data.sales);
    if (data.movements) setMovements(data.movements);
    if (data.closures) setClosures(data.closures);
    if (data.financialSettings) setFinancialSettings(data.financialSettings);
    alert("Datos restaurados correctamente.");
  };

  const navItems = [
    { id: 'pos', icon: ShoppingCart, label: 'Punto de Venta' },
    { id: 'sales-history', icon: ReceiptText, label: 'Historial' },
    { id: 'products', icon: Tag, label: 'Productos' },
    { id: 'inventory', icon: Package, label: 'Inventario' },
    { id: 'stats', icon: BarChart3, label: 'Estadísticas' },
    { id: 'insights', icon: TrendingUp, label: 'Inteligencia' },
    { id: 'settings', icon: SettingsIcon, label: 'Configuración' },
  ];

  const currentRole = roles.find(r => r.id === currentUser?.roleId);
  const filteredNavItems = navItems.filter(item => currentRole?.permissions.includes(item.id as Permission));

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-6">
        <div className="bg-white w-full max-w-md rounded-[3rem] p-10 shadow-2xl animate-in zoom-in duration-500">
          <div className="text-center mb-8">
            <h1 className="text-4xl font-black text-emerald-600 tracking-tighter mb-2">{financialSettings.businessName}</h1>
            <p className="text-slate-400 font-bold uppercase tracking-widest text-xs">Acceso al Sistema</p>
          </div>
          <div className="space-y-4">
            <p className="text-sm font-bold text-slate-500 mb-2">Seleccione Usuario</p>
            {users.map(u => (
              <button
                key={u.id}
                onClick={() => {
                  setCurrentUser(u);
                  const firstPerm = roles.find(r => r.id === u.roleId)?.permissions[0];
                  if (firstPerm) setActiveTab(firstPerm);
                }}
                className="w-full flex items-center justify-between p-5 bg-slate-50 hover:bg-emerald-50 rounded-2xl border-2 border-transparent hover:border-emerald-200 transition-all group"
              >
                <div className="flex items-center gap-4">
                  <div className="w-12 h-12 bg-white rounded-xl flex items-center justify-center text-slate-400 group-hover:text-emerald-500 shadow-sm transition-colors">
                    <UserCircle size={24} />
                  </div>
                  <div className="text-left">
                    <p className="font-black text-slate-800 uppercase tracking-tight">{u.username}</p>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{roles.find(r => r.id === u.roleId)?.name}</p>
                  </div>
                </div>
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      <div className="md:hidden bg-white border-b p-4 flex justify-between items-center sticky top-0 z-50">
        <h1 className="text-xl font-bold text-emerald-600 truncate mr-4">{financialSettings.businessName}</h1>
        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 hover:bg-slate-100 rounded-lg shrink-0">
          {isSidebarOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </div>

      <aside className={`
        fixed inset-y-0 left-0 z-40 w-64 bg-white border-r transform transition-transform duration-300 ease-in-out md:relative md:translate-x-0
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="p-6 h-full flex flex-col">
          <div className="mb-8">
            <h1 className="text-2xl font-bold text-emerald-600 hidden md:block mb-1 tracking-tighter truncate">{financialSettings.businessName}</h1>
            <div className="flex items-center gap-2 px-1">
              <div className={`w-2 h-2 rounded-full ${activeClosure ? 'bg-emerald-500 animate-pulse' : 'bg-red-400'}`}></div>
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{activeClosure ? 'Caja Abierta' : 'Caja Cerrada'}</span>
            </div>
          </div>

          <nav className="space-y-2 flex-1">
            {filteredNavItems.map((item) => (
              <button
                key={item.id}
                onClick={() => {
                  setActiveTab(item.id as Permission);
                  setIsSidebarOpen(false);
                }}
                className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all ${
                  activeTab === item.id 
                    ? 'bg-emerald-50 text-emerald-700 font-semibold shadow-sm' 
                    : 'text-slate-500 hover:bg-slate-50 hover:text-slate-700'
                }`}
              >
                <item.icon size={20} />
                <span>{item.label}</span>
              </button>
            ))}
          </nav>

          <div className="mt-auto pt-4 space-y-4">
            <div className="pt-4 border-t bg-slate-50/50 -mx-6 px-6">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-3">
                  <div className="w-8 h-8 bg-white rounded-lg flex items-center justify-center text-slate-400 border border-slate-100">
                    <UserCircle size={18} />
                  </div>
                  <span className="text-xs font-black text-slate-700 uppercase">{currentUser.username}</span>
                </div>
                <button onClick={() => setCurrentUser(null)} className="p-2 text-slate-400 hover:text-red-500 transition-colors">
                  <LogOut size={18} />
                </button>
              </div>
            </div>
          </div>
        </div>
      </aside>

      <main className="flex-1 overflow-y-auto h-screen relative no-scrollbar">
        <div className="p-4 md:p-8 max-w-7xl mx-auto">
          {activeTab === 'pos' && (
            <POS 
              products={products} 
              categories={categories} 
              onCompleteSale={completeSale} 
              activeClosure={activeClosure}
              onOpenDay={openDay}
              onCloseDay={closeDay}
            />
          )}
          {activeTab === 'sales-history' && (
            <SalesHistory 
              sales={sales} 
              products={products} 
              closures={closures}
              onDeleteSale={deleteSale} 
              dateRange={dateRange} 
              setDateRange={setDateRange} 
            />
          )}
          {activeTab === 'products' && <Products products={products} categories={categories} setProducts={setProducts} setCategories={setCategories} addMovement={addMovement} />}
          {activeTab === 'inventory' && <Inventory movements={movements} products={products} addMovement={addMovement} />}
          {activeTab === 'stats' && <Statistics sales={sales} products={products} categories={categories} closures={closures} settings={financialSettings} setSettings={setFinancialSettings} dateRange={dateRange} setDateRange={setDateRange} />}
          {activeTab === 'insights' && <Insights sales={sales} products={products} categories={categories} />}
          {activeTab === 'settings' && (
            <Settings 
              products={products} categories={categories} sales={sales} movements={movements} financialSettings={financialSettings} setSettings={setFinancialSettings}
              onImport={handleImport} onFactoryReset={() => { localStorage.clear(); window.location.reload(); }} autoSaveConfig={autoSaveConfig} setAutoSaveConfig={setAutoSaveConfig}
              directoryHandle={directoryHandle} setDirectoryHandle={setDirectoryHandle} isSaving={isSaving}
              roles={roles} setRoles={setRoles} users={users} setUsers={setUsers}
            />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Calendar, Search, Banknote, CreditCard, ChevronDown, ReceiptText, Clock, ShoppingBag, Power, TrendingUp, AlertCircle, X, Package, Printer, FileText } from 'lucide-react';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { Sale, Product, DayClosure, ProductClosureSnapshot } from '../types';

interface SalesHistoryProps {
  sales: Sale[];
  products: Product[];
  closures: DayClosure[];
  onDeleteSale: (id: string) => void;
  dateRange: { start: string; end: string };
  setDateRange: React.Dispatch<React.SetStateAction<{ start: string; end: string }>>;
}

const SalesHistory: React.FC<SalesHistoryProps> = ({ sales, products, closures, onDeleteSale, dateRange, setDateRange }) => {
  const [activeView, setActiveView] = useState<'sales' | 'closures'>('sales');
  const [expandedSale, setExpandedSale] = useState<string | null>(null);
  const [expandedClosure, setExpandedClosure] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const todayStr = new Date().toISOString().split('T')[0];

  const filteredSales = useMemo(() => {
    const start = new Date(dateRange.start).setHours(0,0,0,0);
    const end = new Date(dateRange.end).setHours(23, 59, 59, 999);

    return sales.filter(s => {
      const matchesDate = s.date >= start && s.date <= end;
      const matchesSearch = s.id.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           s.items.some(i => i.name.toLowerCase().includes(searchTerm.toLowerCase()));
      return matchesDate && matchesSearch;
    }).sort((a, b) => b.date - a.date);
  }, [sales, dateRange, searchTerm]);

  const filteredClosures = useMemo(() => {
    const start = new Date(dateRange.start).setHours(0,0,0,0);
    const end = new Date(dateRange.end).setHours(23, 59, 59, 999);
    return closures.filter(c => c.startTime >= start && c.startTime <= end)
                  .sort((a, b) => b.startTime - a.startTime);
  }, [closures, dateRange]);

  const todayStats = useMemo(() => {
    const start = new Date(todayStr).setHours(0,0,0,0);
    const end = new Date(todayStr).setHours(23,59,59,999);
    const todaySales = sales.filter(s => s.date >= start && s.date <= end);
    const total = todaySales.reduce((acc, s) => acc + s.total, 0);
    return { total, count: todaySales.length };
  }, [sales, todayStr]);

  const setToday = () => {
    setDateRange({ start: todayStr, end: todayStr });
  };

  const generateClosurePDF = (closure: DayClosure) => {
    const doc = new jsPDF();
    const businessName = localStorage.getItem('gourmet_settings') 
      ? JSON.parse(localStorage.getItem('gourmet_settings')!).businessName 
      : 'GourmetPOS';

    // Header
    doc.setFillColor(16, 185, 129);
    doc.rect(0, 0, 210, 40, 'F');
    doc.setTextColor(255, 255, 255);
    doc.setFontSize(24);
    doc.setFont('helvetica', 'bold');
    doc.text(businessName, 14, 25);

    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    doc.text('REPORTE DE CONTROL DE INVENTARIO Y CAJA', 14, 33);

    // Closure Info
    doc.setTextColor(50, 50, 50);
    doc.setFontSize(12);
    doc.text(`Fecha: ${new Date(closure.startTime).toLocaleDateString()}`, 14, 50);
    doc.text(`Apertura: ${new Date(closure.startTime).toLocaleTimeString()}`, 14, 57);
    doc.text(`Cierre: ${closure.endTime ? new Date(closure.endTime).toLocaleTimeString() : 'En curso'}`, 14, 64);

    // Financial Summary Table
    const totalVentas = closure.totalCashSales + closure.totalTransferSales;
    const esperado = closure.initialCash + closure.totalCashSales;
    const diferencia = (closure.finalCashReal || 0) - esperado;

    autoTable(doc, {
      startY: 75,
      head: [['Concepto Financiero', 'Monto']],
      body: [
        ['Fondo Inicial (Caja)', `$${closure.initialCash.toLocaleString()}`],
        ['Ventas en Efectivo', `$${closure.totalCashSales.toLocaleString()}`],
        ['Ventas por Transferencia', `$${closure.totalTransferSales.toLocaleString()}`],
        ['Total Ventas del Turno', `$${totalVentas.toLocaleString()}`],
        ['Efectivo Esperado', `$${esperado.toLocaleString()}`],
        ['Efectivo Real Contado', `$${closure.finalCashReal?.toLocaleString() || '---'}`],
        ['Diferencia / Balance', { content: `$${diferencia.toLocaleString()}`, styles: { textColor: diferencia < 0 ? [220, 38, 38] : [16, 185, 129], fontStyle: 'bold' } }],
      ],
      theme: 'striped',
      headStyles: { fillColor: [51, 65, 85] },
      margin: { left: 14, right: 14 }
    });

    // Inventory Table
    doc.setFontSize(14);
    doc.setFont('helvetica', 'bold');
    doc.text('Reconciliación de Inventario Alimentos', 14, (doc as any).lastAutoTable.finalY + 15);

    const inventoryBody = (Object.values(closure.productSnapshots) as ProductClosureSnapshot[])
      .filter(s => s.soldQuantity > 0 || s.initialStock > 0)
      .map(s => [
        s.name,
        `${Math.floor(s.initialStock)} ${s.unit}`, // Mostramos el stock inicial como entero solicitado
        `${s.soldQuantity.toFixed(2)} ${s.unit}`,
        `${(s.initialStock - s.soldQuantity).toFixed(2)} ${s.unit}`
      ]);

    autoTable(doc, {
      startY: (doc as any).lastAutoTable.finalY + 20,
      head: [['Producto', 'Stock Inicial (Unid)', 'Cantidad Vendida', 'Stock Final']],
      body: inventoryBody,
      theme: 'grid',
      headStyles: { fillColor: [16, 185, 129] },
      columnStyles: {
        1: { fontStyle: 'bold', halign: 'center' },
        3: { fontStyle: 'bold', textColor: [16, 185, 129], halign: 'right' }
      }
    });

    if (closure.notes) {
      doc.setFontSize(10);
      doc.setTextColor(100);
      doc.text(`Observaciones: ${closure.notes}`, 14, (doc as any).lastAutoTable.finalY + 10);
    }

    doc.save(`Cierre_Alimentos_${new Date(closure.startTime).toISOString().split('T')[0]}.pdf`);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20">
      <header className="flex flex-col xl:flex-row justify-between items-start xl:items-center gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight flex items-center gap-3">
            <ReceiptText className="text-emerald-600" size={32} />
            Historial de Operaciones
          </h2>
          <p className="text-slate-500 font-medium">Revisando ventas del {dateRange.start === dateRange.end ? (dateRange.start === todayStr ? 'Hoy (Día actual)' : dateRange.start) : 'periodo seleccionado'}</p>
        </div>

        <div className="flex flex-col sm:flex-row items-center gap-4 w-full xl:w-auto">
          <button 
            onClick={setToday}
            className={`px-4 py-3 rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all flex items-center gap-2 ${dateRange.start === todayStr && dateRange.end === todayStr ? 'bg-emerald-600 text-white shadow-lg' : 'bg-white text-slate-400 border border-slate-100 hover:bg-slate-50'}`}
          >
            <Clock size={16} />
            Ir a Hoy
          </button>

          <div className="flex items-center gap-2 bg-white p-2 rounded-2xl shadow-sm border border-slate-100 w-full sm:w-auto">
            <Calendar size={18} className="text-slate-400 ml-2" />
            <input 
              type="date" 
              className="bg-transparent border-none focus:ring-0 text-sm font-bold text-slate-700 w-full sm:w-auto"
              value={dateRange.start}
              onChange={e => setDateRange(prev => ({ ...prev, start: e.target.value }))}
            />
            <span className="text-slate-300">|</span>
            <input 
              type="date" 
              className="bg-transparent border-none focus:ring-0 text-sm font-bold text-slate-700 w-full sm:w-auto"
              value={dateRange.end}
              onChange={e => setDateRange(prev => ({ ...prev, end: e.target.value }))}
            />
          </div>
        </div>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-sm flex items-center gap-5">
          <div className="w-14 h-14 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center justify-center shrink-0">
            <TrendingUp size={28} />
          </div>
          <div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Total Hoy ({new Date().toLocaleDateString()})</p>
            <h4 className="text-2xl font-black text-slate-800">${todayStats.total.toLocaleString()}</h4>
          </div>
        </div>
        <div className="bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-sm flex items-center gap-5">
          <div className="w-14 h-14 bg-blue-50 text-blue-600 rounded-2xl flex items-center justify-center shrink-0">
            <ShoppingBag size={28} />
          </div>
          <div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Pedidos Hoy</p>
            <h4 className="text-2xl font-black text-slate-800">{todayStats.count}</h4>
          </div>
        </div>
        <div className="bg-slate-900 p-6 rounded-[2.5rem] shadow-xl flex items-center gap-5">
          <div className="w-14 h-14 bg-white/10 text-emerald-400 rounded-2xl flex items-center justify-center shrink-0">
            <Power size={28} />
          </div>
          <div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Inventario</p>
            <h4 className="text-xl font-black text-white">Sincronizado</h4>
          </div>
        </div>
      </div>

      <div className="flex bg-white p-1.5 rounded-2xl shadow-sm border border-slate-100 w-fit">
        <button onClick={() => setActiveView('sales')} className={`px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeView === 'sales' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-50'}`}>Lista de Ventas</button>
        <button onClick={() => setActiveView('closures')} className={`px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeView === 'closures' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-50'}`}>Cierres & Inventario</button>
      </div>

      {activeView === 'sales' ? (
        <div className="space-y-6">
          <div className="flex justify-between items-center px-4">
             <h3 className="text-xl font-black text-slate-800 flex items-center gap-2"><Clock className="text-emerald-500" /> Línea de Tiempo</h3>
             <div className="relative max-w-xs w-full">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input 
                  type="text" 
                  placeholder="Buscar venta o producto..." 
                  className="w-full pl-10 pr-4 py-3 bg-white border border-slate-200 rounded-2xl text-sm font-bold shadow-sm"
                  value={searchTerm}
                  onChange={e => setSearchTerm(e.target.value)}
                />
             </div>
          </div>

          <div className="bg-white rounded-[3rem] shadow-sm border border-slate-100 overflow-hidden">
            <table className="w-full text-left">
              <thead>
                <tr className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em] border-b border-slate-50">
                  <th className="py-6 pl-10">Fecha / Hora</th>
                  <th className="py-6">Método de Pago</th>
                  <th className="py-6 text-right pr-10">Monto Final</th>
                  <th className="py-6 w-10"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {filteredSales.map(sale => {
                  const isToday = new Date(sale.date).toISOString().split('T')[0] === todayStr;
                  return (
                    <React.Fragment key={sale.id}>
                      <tr onClick={() => setExpandedSale(expandedSale === sale.id ? null : sale.id)} className={`hover:bg-slate-50 cursor-pointer transition-colors ${isToday ? 'bg-emerald-50/20' : ''}`}>
                        <td className="py-6 pl-10">
                          <div className="flex flex-col">
                             <span className="font-black text-slate-800 flex items-center gap-2">
                               {new Date(sale.date).toLocaleDateString()}
                               {isToday && <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span>}
                             </span>
                             <span className="text-[10px] text-slate-400 font-bold uppercase">{new Date(sale.date).toLocaleTimeString()}</span>
                          </div>
                        </td>
                        <td className="py-6">
                          <div className="flex items-center gap-2">
                            {sale.paymentMethod === 'cash' ? <Banknote size={16} className="text-emerald-500" /> : <CreditCard size={16} className="text-blue-500" />}
                            <span className={`px-3 py-1 rounded-xl text-[10px] font-black uppercase ${sale.paymentMethod === 'cash' ? 'bg-emerald-50 text-emerald-600' : 'bg-blue-50 text-blue-600'}`}>
                              {sale.paymentMethod === 'cash' ? 'Efectivo' : 'Transferencia'}
                            </span>
                          </div>
                        </td>
                        <td className="py-6 text-right pr-10 font-black text-slate-900 text-xl">${sale.total.toLocaleString()}</td>
                        <td className="py-6 pr-6">
                          <ChevronDown size={20} className={`text-slate-300 transition-transform ${expandedSale === sale.id ? 'rotate-180' : ''}`} />
